/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications.
 * Supports per-channel settings for email, SMS, and webhook.
 */

import type { NotificationType, NotificationChannel } from './notification.js';

/**
 * Email delivery frequency options.
 * - immediate: Send as soon as the event occurs
 * - daily_digest: Batch into a daily summary
 * - weekly_digest: Batch into a weekly summary
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest';

/**
 * Email-specific notification settings.
 */
export interface EmailPreferences {
  /** Whether email notifications are enabled at all */
  enabled: boolean;
  /** How often to deliver emails */
  frequency: EmailFrequency;
  /** Which notification types the user wants to receive via email */
  subscribedTypes: NotificationType[];
}

/**
 * SMS-specific notification settings.
 */
export interface SmsPreferences {
  /** Whether SMS notifications are enabled */
  enabled: boolean;
  /** Which notification types the user wants to receive via SMS */
  subscribedTypes: NotificationType[];
}

/**
 * Webhook-specific notification settings.
 */
export interface WebhookPreferences {
  /** Whether webhook notifications are enabled */
  enabled: boolean;
  /** Which notification types the user wants to receive via webhook */
  subscribedTypes: NotificationType[];
}

/**
 * Full user notification preferences.
 */
export interface UserPreferences {
  /** Unique ID for the preferences record */
  id: string;
  /** The user these preferences belong to */
  userId: string;
  /** Email notification settings */
  email: EmailPreferences;
  /** SMS notification settings (optional for backward compatibility) */
  sms?: SmsPreferences;
  /** Webhook notification settings (optional for backward compatibility) */
  webhook?: WebhookPreferences;
  /** When preferences were created */
  createdAt: Date;
  /** When preferences were last updated */
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields optional for partial updates.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedTypes?: NotificationType[];
}

/**
 * Input for updating SMS preferences. All fields optional for partial updates.
 */
export interface UpdateSmsPreferencesInput {
  enabled?: boolean;
  subscribedTypes?: NotificationType[];
}

/**
 * Input for updating webhook preferences. All fields optional for partial updates.
 */
export interface UpdateWebhookPreferencesInput {
  enabled?: boolean;
  subscribedTypes?: NotificationType[];
}

/**
 * Input for updating channel preferences generically.
 */
export type UpdateChannelPreferencesInput =
  | { channel: 'email'; preferences: UpdateEmailPreferencesInput }
  | { channel: 'sms'; preferences: UpdateSmsPreferencesInput }
  | { channel: 'webhook'; preferences: UpdateWebhookPreferencesInput };

/**
 * Default email preferences for new users.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedTypes: [
    'order_confirmation',
    'order_status_update',
    'welcome',
    'account_updated',
  ],
};

/**
 * Default SMS preferences for new users.
 * SMS defaults to disabled — users must opt in.
 */
export const DEFAULT_SMS_PREFERENCES: SmsPreferences = {
  enabled: false,
  subscribedTypes: [
    'order_confirmation',
    'order_status_update',
    'welcome',
    'account_updated',
  ],
};

/**
 * Default webhook preferences for new users.
 * Webhook defaults to disabled — users must opt in.
 */
export const DEFAULT_WEBHOOK_PREFERENCES: WebhookPreferences = {
  enabled: false,
  subscribedTypes: [
    'order_confirmation',
    'order_status_update',
    'welcome',
    'account_updated',
  ],
};

