/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences, EmailPreferences, SmsPreferences, WebhookPreferences } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    const prefs: UserPreferences = {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: JSON.parse(record['email'] as string) as EmailPreferences,
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };

    if (record['sms']) {
      prefs.sms = JSON.parse(record['sms'] as string) as SmsPreferences;
    }

    if (record['webhook']) {
      prefs.webhook = JSON.parse(record['webhook'] as string) as WebhookPreferences;
    }

    return prefs;
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      userId: entity.userId,
      email: JSON.stringify(entity.email),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };

    if (entity.sms) {
      record['sms'] = JSON.stringify(entity.sms);
    }

    if (entity.webhook) {
      record['webhook'] = JSON.stringify(entity.webhook);
    }

    return record;
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user notification settings across
 * all channels (email, SMS, webhook). When no preferences exist
 * for a user, returns defaults (email enabled, SMS/webhook disabled).
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  UpdateEmailPreferencesInput,
  UpdateSmsPreferencesInput,
  UpdateWebhookPreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns defaults if none are saved.
   */
  getPreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    this.logger.debug(`No preferences found for user ${userId}, returning defaults`);
    const now = new Date();
    return {
      id: '',
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES, subscribedTypes: [...DEFAULT_EMAIL_PREFERENCES.subscribedTypes] },
      sms: { ...DEFAULT_SMS_PREFERENCES, subscribedTypes: [...DEFAULT_SMS_PREFERENCES.subscribedTypes] },
      webhook: { ...DEFAULT_WEBHOOK_PREFERENCES, subscribedTypes: [...DEFAULT_WEBHOOK_PREFERENCES.subscribedTypes] },
      createdAt: now,
      updatedAt: now,
    };
  }

  /**
   * Update email preferences for a user. Creates preferences if they don't exist.
   */
  updateEmailPreferences(userId: string, input: UpdateEmailPreferencesInput): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);

    if (existing) {
      const updatedEmail = { ...existing.email };
      if (input.enabled !== undefined) updatedEmail.enabled = input.enabled;
      if (input.frequency !== undefined) updatedEmail.frequency = input.frequency;
      if (input.subscribedTypes !== undefined) updatedEmail.subscribedTypes = input.subscribedTypes;

      const updated = this.preferencesRepository.update(existing.id, {
        email: updatedEmail,
        updatedAt: new Date(),
      } as Partial<UserPreferences>);

      this.logger.info(`Updated email preferences for user ${userId}`);
      return updated;
    }

    // Create new preferences record
    const now = new Date();
    const email = {
      ...DEFAULT_EMAIL_PREFERENCES,
      subscribedTypes: [...DEFAULT_EMAIL_PREFERENCES.subscribedTypes],
    };
    if (input.enabled !== undefined) email.enabled = input.enabled;
    if (input.frequency !== undefined) email.frequency = input.frequency;
    if (input.subscribedTypes !== undefined) email.subscribedTypes = input.subscribedTypes;

    const prefs: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email,
      sms: { ...DEFAULT_SMS_PREFERENCES, subscribedTypes: [...DEFAULT_SMS_PREFERENCES.subscribedTypes] },
      webhook: { ...DEFAULT_WEBHOOK_PREFERENCES, subscribedTypes: [...DEFAULT_WEBHOOK_PREFERENCES.subscribedTypes] },
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(prefs);
    this.logger.info(`Created email preferences for user ${userId}`);
    return prefs;
  }

  /**
   * Update SMS preferences for a user. Creates preferences if they don't exist.
   */
  updateSmsPreferences(userId: string, input: UpdateSmsPreferencesInput): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);

    if (existing) {
      const currentSms = existing.sms ?? { ...DEFAULT_SMS_PREFERENCES, subscribedTypes: [...DEFAULT_SMS_PREFERENCES.subscribedTypes] };
      const updatedSms = { ...currentSms };
      if (input.enabled !== undefined) updatedSms.enabled = input.enabled;
      if (input.subscribedTypes !== undefined) updatedSms.subscribedTypes = input.subscribedTypes;

      const updated = this.preferencesRepository.update(existing.id, {
        sms: updatedSms,
        updatedAt: new Date(),
      } as Partial<UserPreferences>);

      this.logger.info(`Updated SMS preferences for user ${userId}`);
      return updated;
    }

    const now = new Date();
    const sms = {
      ...DEFAULT_SMS_PREFERENCES,
      subscribedTypes: [...DEFAULT_SMS_PREFERENCES.subscribedTypes],
    };
    if (input.enabled !== undefined) sms.enabled = input.enabled;
    if (input.subscribedTypes !== undefined) sms.subscribedTypes = input.subscribedTypes;

    const prefs: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES, subscribedTypes: [...DEFAULT_EMAIL_PREFERENCES.subscribedTypes] },
      sms,
      webhook: { ...DEFAULT_WEBHOOK_PREFERENCES, subscribedTypes: [...DEFAULT_WEBHOOK_PREFERENCES.subscribedTypes] },
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(prefs);
    this.logger.info(`Created SMS preferences for user ${userId}`);
    return prefs;
  }

  /**
   * Update webhook preferences for a user. Creates preferences if they don't exist.
   */
  updateWebhookPreferences(userId: string, input: UpdateWebhookPreferencesInput): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);

    if (existing) {
      const currentWebhook = existing.webhook ?? { ...DEFAULT_WEBHOOK_PREFERENCES, subscribedTypes: [...DEFAULT_WEBHOOK_PREFERENCES.subscribedTypes] };
      const updatedWebhook = { ...currentWebhook };
      if (input.enabled !== undefined) updatedWebhook.enabled = input.enabled;
      if (input.subscribedTypes !== undefined) updatedWebhook.subscribedTypes = input.subscribedTypes;

      const updated = this.preferencesRepository.update(existing.id, {
        webhook: updatedWebhook,
        updatedAt: new Date(),
      } as Partial<UserPreferences>);

      this.logger.info(`Updated webhook preferences for user ${userId}`);
      return updated;
    }

    const now = new Date();
    const webhook = {
      ...DEFAULT_WEBHOOK_PREFERENCES,
      subscribedTypes: [...DEFAULT_WEBHOOK_PREFERENCES.subscribedTypes],
    };
    if (input.enabled !== undefined) webhook.enabled = input.enabled;
    if (input.subscribedTypes !== undefined) webhook.subscribedTypes = input.subscribedTypes;

    const prefs: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES, subscribedTypes: [...DEFAULT_EMAIL_PREFERENCES.subscribedTypes] },
      sms: { ...DEFAULT_SMS_PREFERENCES, subscribedTypes: [...DEFAULT_SMS_PREFERENCES.subscribedTypes] },
      webhook,
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(prefs);
    this.logger.info(`Created webhook preferences for user ${userId}`);
    return prefs;
  }

  /**
   * Check if a user should receive a specific notification type via email.
   * Kept for backward compatibility — delegates to shouldSend().
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    return this.shouldSend(userId, notificationType, 'email');
  }

  /**
   * Check if a user should receive a notification via a specific channel.
   * Returns true if no preferences exist for the channel (backward-compatible default).
   */
  shouldSend(userId: string, notificationType: NotificationType, channel: NotificationChannel): boolean {
    const prefs = this.getPreferences(userId);

    switch (channel) {
      case 'email':
        if (!prefs.email.enabled) return false;
        return prefs.email.subscribedTypes.includes(notificationType);

      case 'sms': {
        const smsPrefs = prefs.sms ?? DEFAULT_SMS_PREFERENCES;
        if (!smsPrefs.enabled) return false;
        return smsPrefs.subscribedTypes.includes(notificationType);
      }

      case 'webhook': {
        const webhookPrefs = prefs.webhook ?? DEFAULT_WEBHOOK_PREFERENCES;
        if (!webhookPrefs.enabled) return false;
        return webhookPrefs.subscribedTypes.includes(notificationType);
      }

      default:
        // Unknown channels (e.g., in-app) — allow by default
        return true;
    }
  }
}

