import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../../src/models/user-preferences.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let preferencesRepo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    preferencesRepo = new PreferencesRepository(db);
    service = new PreferencesService(preferencesRepo);
    resetPreferencesIdCounter();
  });

  describe('getPreferences', () => {
    it('should return default preferences when none exist', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedTypes).toEqual(DEFAULT_EMAIL_PREFERENCES.subscribedTypes);
    });

    it('should return saved preferences when they exist', () => {
      service.updateEmailPreferences('user-1', {
        frequency: 'daily_digest',
      });

      const prefs = service.getPreferences('user-1');
      expect(prefs.email.frequency).toBe('daily_digest');
      expect(prefs.email.enabled).toBe(true);
    });

    it('should return default SMS preferences (disabled) when none exist', () => {
      const prefs = service.getPreferences('user-1');
      expect(prefs.sms?.enabled).toBe(false);
      expect(prefs.sms?.subscribedTypes).toEqual(DEFAULT_SMS_PREFERENCES.subscribedTypes);
    });

    it('should return default webhook preferences (disabled) when none exist', () => {
      const prefs = service.getPreferences('user-1');
      expect(prefs.webhook?.enabled).toBe(false);
      expect(prefs.webhook?.subscribedTypes).toEqual(DEFAULT_WEBHOOK_PREFERENCES.subscribedTypes);
    });
  });

  describe('updateEmailPreferences', () => {
    it('should create preferences on first update', () => {
      const prefs = service.updateEmailPreferences('user-1', {
        enabled: false,
      });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(false);
      expect(prefs.email.frequency).toBe('immediate');
    });

    it('should update existing preferences', () => {
      service.updateEmailPreferences('user-1', { enabled: true });
      const updated = service.updateEmailPreferences('user-1', {
        frequency: 'weekly_digest',
      });

      expect(updated.email.frequency).toBe('weekly_digest');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update subscribed types', () => {
      const prefs = service.updateEmailPreferences('user-1', {
        subscribedTypes: ['order_confirmation', 'welcome'],
      });

      expect(prefs.email.subscribedTypes).toEqual(['order_confirmation', 'welcome']);
    });

    it('should generate sequential IDs', () => {
      const p1 = service.updateEmailPreferences('user-1', {});
      const p2 = service.updateEmailPreferences('user-2', {});

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });

    it('should not generate new ID when updating existing preferences', () => {
      const created = service.updateEmailPreferences('user-1', { enabled: true });
      const updated = service.updateEmailPreferences('user-1', { enabled: false });

      expect(updated.id).toBe(created.id);
    });

    it('should preserve other fields when partially updating', () => {
      service.updateEmailPreferences('user-1', {
        frequency: 'daily_digest',
        subscribedTypes: ['order_confirmation'],
      });

      const updated = service.updateEmailPreferences('user-1', {
        enabled: false,
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('daily_digest');
      expect(updated.email.subscribedTypes).toEqual(['order_confirmation']);
    });

    it('should include default SMS and webhook preferences when creating new record', () => {
      const prefs = service.updateEmailPreferences('user-1', { enabled: true });

      expect(prefs.sms?.enabled).toBe(false);
      expect(prefs.webhook?.enabled).toBe(false);
    });
  });

  describe('updateSmsPreferences', () => {
    it('should create preferences with SMS enabled on first update', () => {
      const prefs = service.updateSmsPreferences('user-1', { enabled: true });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.sms?.enabled).toBe(true);
      expect(prefs.sms?.subscribedTypes).toEqual(DEFAULT_SMS_PREFERENCES.subscribedTypes);
    });

    it('should update existing SMS preferences', () => {
      service.updateSmsPreferences('user-1', { enabled: true });
      const updated = service.updateSmsPreferences('user-1', {
        subscribedTypes: ['order_confirmation'],
      });

      expect(updated.sms?.enabled).toBe(true);
      expect(updated.sms?.subscribedTypes).toEqual(['order_confirmation']);
    });

    it('should preserve email preferences when updating SMS', () => {
      service.updateEmailPreferences('user-1', { frequency: 'daily_digest' });
      const updated = service.updateSmsPreferences('user-1', { enabled: true });

      expect(updated.email.frequency).toBe('daily_digest');
      expect(updated.sms?.enabled).toBe(true);
    });

    it('should initialize SMS defaults when updating existing record without SMS', () => {
      service.updateEmailPreferences('user-1', { enabled: true });
      const updated = service.updateSmsPreferences('user-1', { enabled: true });

      expect(updated.sms?.enabled).toBe(true);
      expect(updated.sms?.subscribedTypes).toEqual(DEFAULT_SMS_PREFERENCES.subscribedTypes);
    });
  });

  describe('updateWebhookPreferences', () => {
    it('should create preferences with webhook enabled on first update', () => {
      const prefs = service.updateWebhookPreferences('user-1', { enabled: true });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.webhook?.enabled).toBe(true);
      expect(prefs.webhook?.subscribedTypes).toEqual(DEFAULT_WEBHOOK_PREFERENCES.subscribedTypes);
    });

    it('should update existing webhook preferences', () => {
      service.updateWebhookPreferences('user-1', { enabled: true });
      const updated = service.updateWebhookPreferences('user-1', {
        subscribedTypes: ['welcome'],
      });

      expect(updated.webhook?.enabled).toBe(true);
      expect(updated.webhook?.subscribedTypes).toEqual(['welcome']);
    });

    it('should preserve email and SMS preferences when updating webhook', () => {
      service.updateEmailPreferences('user-1', { frequency: 'daily_digest' });
      service.updateSmsPreferences('user-1', { enabled: true });
      const updated = service.updateWebhookPreferences('user-1', { enabled: true });

      expect(updated.email.frequency).toBe('daily_digest');
      expect(updated.sms?.enabled).toBe(true);
      expect(updated.webhook?.enabled).toBe(true);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true by default for all notification types', () => {
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'order_status_update')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'account_updated')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false for unsubscribed notification types', () => {
      service.updateEmailPreferences('user-1', {
        subscribedTypes: ['order_confirmation'],
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(false);
    });
  });

  describe('shouldSend (multi-channel)', () => {
    it('should return false for SMS by default (opt-in model)', () => {
      expect(service.shouldSend('user-1', 'order_confirmation', 'sms')).toBe(false);
    });

    it('should return false for webhook by default (opt-in model)', () => {
      expect(service.shouldSend('user-1', 'order_confirmation', 'webhook')).toBe(false);
    });

    it('should return true for email by default (opt-out model)', () => {
      expect(service.shouldSend('user-1', 'order_confirmation', 'email')).toBe(true);
    });

    it('should return true for SMS when user opts in', () => {
      service.updateSmsPreferences('user-1', { enabled: true });
      expect(service.shouldSend('user-1', 'order_confirmation', 'sms')).toBe(true);
    });

    it('should return true for webhook when user opts in', () => {
      service.updateWebhookPreferences('user-1', { enabled: true });
      expect(service.shouldSend('user-1', 'order_confirmation', 'webhook')).toBe(true);
    });

    it('should respect per-channel subscribed types for SMS', () => {
      service.updateSmsPreferences('user-1', {
        enabled: true,
        subscribedTypes: ['order_confirmation'],
      });

      expect(service.shouldSend('user-1', 'order_confirmation', 'sms')).toBe(true);
      expect(service.shouldSend('user-1', 'welcome', 'sms')).toBe(false);
    });

    it('should respect per-channel subscribed types for webhook', () => {
      service.updateWebhookPreferences('user-1', {
        enabled: true,
        subscribedTypes: ['welcome'],
      });

      expect(service.shouldSend('user-1', 'welcome', 'webhook')).toBe(true);
      expect(service.shouldSend('user-1', 'order_confirmation', 'webhook')).toBe(false);
    });

    it('should allow unknown channels by default', () => {
      expect(service.shouldSend('user-1', 'order_confirmation', 'in-app')).toBe(true);
    });

    it('should handle independent per-channel settings', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      service.updateSmsPreferences('user-1', { enabled: true });

      expect(service.shouldSend('user-1', 'order_confirmation', 'email')).toBe(false);
      expect(service.shouldSend('user-1', 'order_confirmation', 'sms')).toBe(true);
    });
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let emailAdapter: EmailAdapter;
  let preferencesService: PreferencesService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);
    resetNotificationIdCounter();
    resetPreferencesIdCounter();

    const preferencesRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(preferencesRepo);
    notificationService.setPreferencesService(preferencesService);
  });

  it('should send notification when user has default preferences', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const emails = emailAdapter.getSentEmails();
    expect(emails).toHaveLength(1);
    expect(emails[0]?.to).toBe('alice@example.com');
  });

  it('should skip notification when user has disabled email', async () => {
    preferencesService.updateEmailPreferences('user-1', { enabled: false });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const emails = emailAdapter.getSentEmails();
    expect(emails).toHaveLength(0);
  });

  it('should skip notification when user unsubscribed from type', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedTypes: ['welcome'],
    });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const emails = emailAdapter.getSentEmails();
    expect(emails).toHaveLength(0);
  });

  it('should send welcome email when user is subscribed to it', async () => {
    const event: UserCreatedEvent = {
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Bob',
        email: 'bob@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const emails = emailAdapter.getSentEmails();
    expect(emails).toHaveLength(1);
    expect(emails[0]?.subject).toBe('Welcome to TaskFlow Pro');
  });

  it('should still send notifications without preferences service configured', async () => {
    const plainService = new NotificationService(new EventBus());
    const adapter = new EmailAdapter();
    plainService.registerAdapter(adapter);

    const result = await plainService.send({
      id: 'test-1',
      type: 'order_confirmation',
      channel: 'email',
      recipient: 'test@example.com',
      subject: 'Test',
      body: 'Test body',
      priority: 'normal',
      createdAt: new Date(),
      metadata: { userId: 'user-1' },
    });

    expect(result.success).toBe(true);
    expect(adapter.getSentEmails()).toHaveLength(1);
  });

  it('should skip SMS when user has not opted into SMS', async () => {
    const smsAdapter = new SmsAdapter();
    notificationService.registerAdapter(smsAdapter);

    const result = await notificationService.send({
      id: 'test-sms-1',
      type: 'order_confirmation',
      channel: 'sms',
      recipient: '+1234567890',
      subject: 'Order Confirmation',
      body: 'Your order was placed.',
      priority: 'normal',
      createdAt: new Date(),
      metadata: { userId: 'user-1' },
    });

    expect(result.success).toBe(true);
    expect(smsAdapter.getSentMessages()).toHaveLength(0);
  });

  it('should send SMS when user has opted into SMS', async () => {
    const smsAdapter = new SmsAdapter();
    notificationService.registerAdapter(smsAdapter);
    preferencesService.updateSmsPreferences('user-1', { enabled: true });

    const result = await notificationService.send({
      id: 'test-sms-2',
      type: 'order_confirmation',
      channel: 'sms',
      recipient: '+1234567890',
      subject: 'Order Confirmation',
      body: 'Your order was placed.',
      priority: 'normal',
      createdAt: new Date(),
      metadata: { userId: 'user-1' },
    });

    expect(result.success).toBe(true);
    expect(smsAdapter.getSentMessages()).toHaveLength(1);
  });

  it('should skip webhook when user has not opted into webhook', async () => {
    const webhookAdapter = new WebhookAdapter();
    notificationService.registerAdapter(webhookAdapter);

    const result = await notificationService.send({
      id: 'test-webhook-1',
      type: 'order_confirmation',
      channel: 'webhook',
      recipient: 'https://example.com/hook',
      subject: 'Order Confirmation',
      body: 'Your order was placed.',
      priority: 'normal',
      createdAt: new Date(),
      metadata: { userId: 'user-1' },
    });

    expect(result.success).toBe(true);
    expect(webhookAdapter.getSentWebhooks()).toHaveLength(0);
  });

  it('should send webhook when user has opted into webhook', async () => {
    const webhookAdapter = new WebhookAdapter();
    notificationService.registerAdapter(webhookAdapter);
    preferencesService.updateWebhookPreferences('user-1', { enabled: true });

    const result = await notificationService.send({
      id: 'test-webhook-2',
      type: 'order_confirmation',
      channel: 'webhook',
      recipient: 'https://example.com/hook',
      subject: 'Order Confirmation',
      body: 'Your order was placed.',
      priority: 'normal',
      createdAt: new Date(),
      metadata: { userId: 'user-1' },
    });

    expect(result.success).toBe(true);
    expect(webhookAdapter.getSentWebhooks()).toHaveLength(1);
  });

  it('should independently check per-channel preferences', async () => {
    const smsAdapter = new SmsAdapter();
    notificationService.registerAdapter(smsAdapter);

    // Disable email, enable SMS
    preferencesService.updateEmailPreferences('user-1', { enabled: false });
    preferencesService.updateSmsPreferences('user-1', { enabled: true });

    const emailResult = await notificationService.send({
      id: 'test-email-1',
      type: 'order_confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test body',
      priority: 'normal',
      createdAt: new Date(),
      metadata: { userId: 'user-1' },
    });

    const smsResult = await notificationService.send({
      id: 'test-sms-3',
      type: 'order_confirmation',
      channel: 'sms',
      recipient: '+1234567890',
      subject: 'Test',
      body: 'Test body',
      priority: 'normal',
      createdAt: new Date(),
      metadata: { userId: 'user-1' },
    });

    // Email should be skipped (disabled), SMS should be sent (enabled)
    expect(emailAdapter.getSentEmails()).toHaveLength(0);
    expect(smsAdapter.getSentMessages()).toHaveLength(1);
  });
});
